import React from 'react';
import Logo from './Logo.png'; 
import Menu, { Lunch } from './Menu'; 

function App() {
  // THE TRUE TERRACOTTA: Earthy, muted, used ONLY as a tiny accent
  const accentColor = '#9E5B40'; 

  return (
    <div style={{ backgroundColor: '#0D0D0D', minHeight: '100vh', margin: 0, padding: 0, fontFamily: 'Helvetica, Arial, sans-serif', color: '#fff' }}>
      
      {/* 1. THE NAVBAR (EXACT REPLICA OF THE IMAGE) */}
      <nav style={{ 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center', 
        padding: '15px 40px', 
        backgroundColor: '#111', 
        borderBottom: '1px solid #1a1a1a',
        position: 'sticky',
        top: 0,
        zIndex: 1000
      }}>
        {/* LOGO AREA */}
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
          <img src={Logo} alt="Àmí by T" style={{ height: '40px', filter: 'brightness(1.1)' }} />
          <div style={{ lineHeight: '1' }}>
            <div style={{ fontSize: '1.2rem', fontWeight: 'bold', letterSpacing: '1px' }}>Àmí</div>
            <div style={{ fontSize: '0.6rem', color: '#666' }}>by T</div>
          </div>
        </div>

        {/* NAV LINKS */}
        <div style={{ display: 'flex', gap: '25px' }}>
          {['Home', 'Small Chops', 'Office Lunch', 'About Us'].map((link) => (
            <a key={link} href={`#${link}`} style={{ color: '#aaa', textDecoration: 'none', fontSize: '0.85rem' }}>{link}</a>
          ))}
        </div>

        {/* CART BUTTON */}
        <div style={{ backgroundColor: '#33211C', color: accentColor, padding: '6px 15px', borderRadius: '20px', fontSize: '0.75rem', border: `1px solid ${accentColor}` }}>
          3 items
        </div>
      </nav>

      {/* 2. THE CONTENT AREA (MOVED UP) */}
      <main style={{ maxWidth: '1200px', margin: '0 auto', padding: '40px 20px' }}>
        
        {/* SECTION HEADER */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' }}>
          <h2 style={{ fontSize: '2rem', fontWeight: '300', margin: 0 }}>Featured Categories</h2>
          <button style={{ background: 'none', border: '1px solid #333', color: '#fff', padding: '5px 15px', borderRadius: '15px', fontSize: '0.7rem' }}>Show All ›</button>
        </div>

        {/* THE GRID (MATCHING THE IMAGE) */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(450px, 1fr))', gap: '20px' }}>
          
          {/* CATEGORY 1: SMALL CHOPS */}
          <div style={{ backgroundColor: '#161616', borderRadius: '8px', padding: '25px', border: '1px solid #222' }}>
            <h3 style={{ fontSize: '1.4rem', color: accentColor, marginBottom: '20px', textAlign: 'center', fontWeight: '400' }}>The Àmí Starter Pack</h3>
            <Menu />
            <div style={{ textAlign: 'center', marginTop: '20px' }}>
               <button style={{ backgroundColor: 'transparent', border: `1px solid ${accentColor}`, color: accentColor, padding: '10px 30px', borderRadius: '20px', cursor: 'pointer' }}>Starter Now</button>
            </div>
          </div>

          {/* CATEGORY 2: LUNCH */}
          <div style={{ backgroundColor: '#161616', borderRadius: '8px', padding: '25px', border: '1px solid #222' }}>
            <h3 style={{ fontSize: '1.4rem', color: accentColor, marginBottom: '20px', textAlign: 'center', fontWeight: '400' }}>Office Lunch Subscriptions</h3>
            <Lunch />
             <div style={{ textAlign: 'center', marginTop: '20px' }}>
               <button style={{ backgroundColor: 'transparent', border: `1px solid ${accentColor}`, color: accentColor, padding: '10px 30px', borderRadius: '20px', cursor: 'pointer' }}>Order Now</button>
            </div>
          </div>

        </div>
      </main>

      {/* 3. FOOTER */}
      <footer style={{ textAlign: 'center', padding: '60px', color: '#444', fontSize: '0.7rem', borderTop: '1px solid #111' }}>
        <p>© 2026 ÀMÍ BY T | LAGOS</p>
      </footer>

    </div>
  );
}

export default App;
